 37→/**
 38→ * Allows a user to edit the [deck description][description]
 39→ *
 40→ * This is visible on [StudyOptionsFragment]
 41→ */
 42→class EditDeckDescriptionDialog : DialogFragment() {
 43→    private val deckId: DeckId
 44→        get() = requireArguments().getLong(ARG_DECK_ID)
 45→
 46→    private lateinit var deckDescriptionInput: TextInputEditText
 47→
 48→    private var currentDescription
 49→        get() = deckDescriptionInput.text.toString()
 50→        set(value) { deckDescriptionInput.setText(value) }
 51→
 52→    override fun onCreateView(
 53→        inflater: LayoutInflater,
 54→        container: ViewGroup?,
 55→        savedInstanceState: Bundle?
 56→    ): View {
 57→        Themes.setTheme(requireContext())
 58→        return inflater.inflate(R.layout.dialog_deck_description, null).apply {
 59→            deckDescriptionInput = this.findViewById(R.id.deck_description_input)
 60→            launchCatchingTask {
 61→                currentDescription = getDescription()
 62→            }
 63→            findViewById<MaterialToolbar>(R.id.topAppBar).apply {
 64→                setNavigationOnClickListener {
 65→                    onBack()
 66→                }
 67→
 68→                setOnMenuItemClickListener { menuItem ->
 69→                    if (menuItem.itemId == R.id.action_save) {
 70→                        saveAndExit()
 71→                        true
 72→                    } else {
 73→                        false
 74→                    }
 75→                }
 76→            }.also { toolbar ->
 77→                launchCatchingTask { toolbar.title = withCol { decks.get(deckId)!!.name } }
 78→            }
 79→        }
 80→    }
 81→
 82→    override fun onStart() {
 83→        super.onStart()
 84→
 85→        dialog!!.window!!.setLayout(
 86→            ViewGroup.LayoutParams.MATCH_PARENT,
 87→            ViewGroup.LayoutParams.WRAP_CONTENT
 88→        )
 89→    }
 90→
 91→    private fun saveAndExit() = launchCatchingTask {
 92→        setDescription(currentDescription)
 93→        Timber.i("closing deck description dialog")
 94→        dismiss()
 95→    }
 96→
 97→    private fun onBack() = launchCatchingTask {
 98→        fun closeWithoutSaving() {
 99→            Timber.i("Closing dialog without saving")
100→            dismiss()
101→        }
102→
103→        if (getDescription() == currentDescription) {
104→            closeWithoutSaving()
105→            return@launchCatchingTask
106→        }
107→
108→        Timber.i("asking if user should discard changes")
109→        DiscardChangesDialog.showDialog(requireContext()) {
110→            closeWithoutSaving()
111→        }
112→    }
113→
114→    private suspend fun getDescription() = withCol { decks.get(deckId)!!.description }
115→
116→    private suspend fun setDescription(value: String) {
117→        Timber.i("updating deck description")
118→        withCol { decks.update(deckId) { description = value } }
119→    }
120→
121→    companion object {
122→        private const val ARG_DECK_ID = "deckId"
123→
124→        fun newInstance(deckId: DeckId): EditDeckDescriptionDialog {
125→            return EditDeckDescriptionDialog().apply {
126→                arguments = bundleOf(
127→                    ARG_DECK_ID to deckId
128→                )
129→            }
130→        }
131→    }
132→}
